import type { CSSObject, CSSValueInput, Rule, RuleContext } from '@unocss/core'
import type { Theme } from '../theme'
import { colorableShadows, colorResolver, defineProperty, getStringComponent, globalKeywords, h, isCSSMathFn, numberResolver } from '../utils'
import { bracketTypeRe } from '../utils/handlers/regex'
import { generateThemeVariable, themeTracking } from '../utils/track'

export const fonts: Rule<Theme>[] = [
  // text
  [/^text-(.+)$/, handleText, { autocomplete: 'text-$text' }],

  // // text size
  [/^(?:text|font)-size-(.+)$/, handleSize, { autocomplete: 'text-size-$text' }],

  // text colors
  [/^text-(?:color-)?(.+)$/, handlerColorOrSize, { autocomplete: 'text-$colors' }],

  // colors
  [/^(?:color|c)-(.+)$/, colorResolver('color', 'text')],

  // style
  [/^(?:text|color|c)-(.+)$/, ([, v]) => globalKeywords.includes(v) ? { color: v } : undefined, { autocomplete: `(text|color|c)-(${globalKeywords.join('|')})` }],

  // opacity
  [/^(?:text|color|c)-op(?:acity)?-?(.+)$/, ([, opacity]) => ({ '--un-text-opacity': h.bracket.percent.cssvar(opacity) }), { autocomplete: '(text|color|c)-(op|opacity)-<percent>' }],

  // weights
  [
    /^fw-?([^-]+)$/,
    ([, s], { theme }) => {
      let v: string | undefined

      if (theme.fontWeight?.[s]) {
        themeTracking(`fontWeight`, s)
        v = generateThemeVariable('fontWeight', s)
      }
      else {
        v = h.bracket.cssvar.global.number(s)
      }

      return {
        '--un-font-weight': v,
        'font-weight': v,
      }
    },
    {
      autocomplete: [
        '(font|fw)-(100|200|300|400|500|600|700|800|900)',
        '(font|fw)-$fontWeight',
      ],
    },
  ],

  // leadings
  [
    /^(?:font-)?(?:leading|lh|line-height)-(.+)$/,
    ([, s], { theme }) => {
      let v: string | undefined

      if (theme.leading?.[s]) {
        themeTracking('leading', s)
        v = generateThemeVariable('leading', s)
      }
      else if (numberResolver(s)) {
        themeTracking('spacing')
        v = `calc(var(--spacing) * ${numberResolver(s)})`
      }
      else {
        v = h.bracket.cssvar.global.rem(s)
      }

      if (v != null) {
        return [
          {
            '--un-leading': v,
            'line-height': v,
          },
          defineProperty('--un-leading'),
        ]
      }
    },
    { autocomplete: '(leading|lh|line-height)-$leading' },
  ],

  // synthesis
  ['font-synthesis-weight', { 'font-synthesis': 'weight' }],
  ['font-synthesis-style', { 'font-synthesis': 'style' }],
  ['font-synthesis-small-caps', { 'font-synthesis': 'small-caps' }],
  ['font-synthesis-none', { 'font-synthesis': 'none' }],
  [/^font-synthesis-(.+)$/, ([, s]) => ({ 'font-synthesis': h.bracket.cssvar.global(s) })],

  // tracking
  [
    /^(?:font-)?tracking-(.+)$/,
    ([, s], { theme }) => {
      let v: string | undefined

      if (theme.tracking?.[s]) {
        themeTracking(`tracking`, s)
        v = generateThemeVariable('tracking', s)
      }
      else {
        v = h.bracket.cssvar.global.rem(s)
      }

      return {
        '--un-tracking': v,
        'letter-spacing': v,
      }
    },
    { autocomplete: 'tracking-$tracking' },
  ],

  // word-spacing
  [
    /^(?:font-)?word-spacing-(.+)$/,
    ([, s], { theme }) => {
      // Use the same variable as tracking
      const v = theme.tracking?.[s] ? generateThemeVariable('tracking', s) : h.bracket.cssvar.global.rem(s)
      return {
        '--un-word-spacing': v,
        'word-spacing': v,
      }
    },
    { autocomplete: 'word-spacing-$spacing' },
  ],

  // stretch
  ['font-stretch-normal', { 'font-stretch': 'normal' }],
  ['font-stretch-ultra-condensed', { 'font-stretch': 'ultra-condensed' }],
  ['font-stretch-extra-condensed', { 'font-stretch': 'extra-condensed' }],
  ['font-stretch-condensed', { 'font-stretch': 'condensed' }],
  ['font-stretch-semi-condensed', { 'font-stretch': 'semi-condensed' }],
  ['font-stretch-semi-expanded', { 'font-stretch': 'semi-expanded' }],
  ['font-stretch-expanded', { 'font-stretch': 'expanded' }],
  ['font-stretch-extra-expanded', { 'font-stretch': 'extra-expanded' }],
  ['font-stretch-ultra-expanded', { 'font-stretch': 'ultra-expanded' }],
  [
    /^font-stretch-(.+)$/,
    ([, s]) => ({ 'font-stretch': h.bracket.cssvar.fraction.global(s) }),
    { autocomplete: 'font-stretch-<percentage>' },
  ],

  // family & weight
  [
    /^font-(.+)$/,
    ([, d], { theme }) => {
      let v: string | undefined

      // Prefer theme font family
      if (theme.font?.[d]) {
        themeTracking('font', d)
        v = generateThemeVariable('font', d)
        return { 'font-family': v }
      }

      // Prefer theme font weight
      if (theme.fontWeight?.[d]) {
        themeTracking('fontWeight', d)
        v = generateThemeVariable('fontWeight', d)
        return { '--un-font-weight': v, 'font-weight': v }
      }

      // Numeric font weight (e.g. font-700)
      v = h.number(d)
      if (v != null) {
        return { '--un-font-weight': v, 'font-weight': v }
      }

      // Bracketed font family (e.g. font-[family:Inter])
      v = h.bracketOfFamily(d)
      if (v != null && h.number(v) == null) {
        v = h.cssvar(v) ?? v
        return { 'font-family': v }
      }

      // Bracketed numeric font weight (e.g. font-[number:700])
      v = h.bracketOfNumber(d)
      if (v != null) {
        v = h.cssvar.number(v)
        return { '--un-font-weight': v, 'font-weight': v }
      }

      // Bracketed value that is a unknown (e.g. font-[sth])
      v = h.bracket(d)
      if (v != null && h.number(v) != null) {
        const num = h.number(v)
        return { '--un-font-weight': num, 'font-weight': num }
      }

      v = h.bracket.cssvar.global(d)
      if (v != null) {
        return { 'font-family': v }
      }
    },
    { autocomplete: ['font-$font', 'font-$fontWeight'] },
  ],
]

export const tabSizes: Rule<Theme>[] = [
  [/^tab(?:-(.+))?$/, ([, s]) => {
    const v = h.bracket.cssvar.global.number(s || '4')
    if (v != null) {
      return {
        '-moz-tab-size': v,
        '-o-tab-size': v,
        'tab-size': v,
      }
    }
  }],
]

export const textIndents: Rule<Theme>[] = [
  [/^indent-(.+)$/, ([, s]) => {
    let v: string | number | undefined = numberResolver(s)

    if (v != null) {
      themeTracking(`spacing`)
      return { 'text-indent': `calc(var(--spacing) * ${v})` }
    }

    v = h.bracket.cssvar.auto.global.rem(s)

    if (v != null) {
      return { 'text-indent': v }
    }
  }],
]

export const textStrokes: Rule<Theme>[] = [
  // widths
  [/^text-stroke(?:-(.+))?$/, ([, s = 'DEFAULT'], { theme }) => {
    if (theme.textStrokeWidth?.[s]) {
      themeTracking(`textStrokeWidth`, s)
    }
    return {
      '-webkit-text-stroke-width': theme.textStrokeWidth?.[s]
        ? generateThemeVariable('textStrokeWidth', s)
        : h.bracket.cssvar.px(s),
    }
  }, { autocomplete: 'text-stroke-$textStrokeWidth' }],

  // colors
  [/^text-stroke-(.+)$/, colorResolver('-webkit-text-stroke-color', 'text-stroke'), { autocomplete: 'text-stroke-$colors' }],
  [/^text-stroke-op(?:acity)?-?(.+)$/, ([, opacity]) => ({ '--un-text-stroke-opacity': h.bracket.percent.cssvar(opacity) }), { autocomplete: 'text-stroke-(op|opacity)-<percent>' }],
]

const opRE = /op(?:acity)?-/
export const textShadows: Rule<Theme>[] = [
  [/^text-shadow(?:-(.+))?$/, (match, ctx) => {
    const [_, s = 'DEFAULT'] = match
    const v = ctx.theme.textShadow?.[s]
    if (v != null) {
      return {
        '--un-text-shadow': colorableShadows(v, '--un-text-shadow-color').join(','),
        'text-shadow': 'var(--un-text-shadow)',
      }
    }
    if (opRE.test(s))
      return { '--un-text-shadow-opacity': h.bracket.percent.cssvar(s.replace(opRE, '')) }

    return colorResolver('--un-text-shadow-color', 'text-shadow')(match, ctx) ?? { 'text-shadow': h.bracket.cssvar.global(s) }
  }, {
    autocomplete: [
      'text-shadow-$textShadow',
      'text-shadow(-color)?-$colors',
      'text-shadow(-color)?-(op|opacity)-<percent>',
    ],
  }],

  // colors
  [/^text-shadow-color-(.+)$/, colorResolver('--un-text-shadow-color', 'text-shadow'), { autocomplete: 'text-shadow-color-$colors' }],
  [/^text-shadow-color-op(?:acity)?-?(.+)$/, ([, opacity]) => ({ '--un-text-shadow-opacity': h.bracket.percent.cssvar(opacity) }), { autocomplete: 'text-shadow-color-(op|opacity)-<percent>' }],
]

const fontVariantNumericProperties = [
  defineProperty('--un-ordinal'),
  defineProperty('--un-slashed-zero'),
  defineProperty('--un-numeric-figure'),
  defineProperty('--un-numeric-spacing'),
  defineProperty('--un-numeric-fraction'),
]
const baseFontVariantNumeric = {
  'font-variant-numeric': 'var(--un-ordinal,) var(--un-slashed-zero,) var(--un-numeric-figure,) var(--un-numeric-spacing,) var(--un-numeric-fraction,)',
}

export const fontVariantNumeric: Rule<Theme>[] = [
  ['ordinal', [{ '--un-ordinal': 'ordinal', ...baseFontVariantNumeric }, ...fontVariantNumericProperties]],
  ['slashed-zero', [{ '--un-slashed-zero': 'slashed-zero', ...baseFontVariantNumeric }, ...fontVariantNumericProperties]],
  ['lining-nums', [{ '--un-numeric-figure': 'lining-nums', ...baseFontVariantNumeric }, ...fontVariantNumericProperties]],
  ['oldstyle-nums', [{ '--un-numeric-figure': 'oldstyle-nums', ...baseFontVariantNumeric }, ...fontVariantNumericProperties]],
  ['proportional-nums', [{ '--un-numeric-spacing': 'proportional-nums', ...baseFontVariantNumeric }, ...fontVariantNumericProperties]],
  ['tabular-nums', [{ '--un-numeric-spacing': 'tabular-nums', ...baseFontVariantNumeric }, ...fontVariantNumericProperties]],
  ['diagonal-fractions', [{ '--un-numeric-fraction': 'diagonal-fractions', ...baseFontVariantNumeric }, ...fontVariantNumericProperties]],
  ['stacked-fractions', [{ '--un-numeric-fraction': 'stacked-fractions', ...baseFontVariantNumeric }, ...fontVariantNumericProperties]],
  ['normal-nums', [{ 'font-variant-numeric': 'normal' }]],
]

function handleText([, s = 'base']: string[], { theme }: RuleContext<Theme>): CSSObject | undefined {
  const split = splitShorthand(s, 'length')
  if (!split)
    return

  const [size, leading] = split

  const sizePairs = theme.text?.[size]
  let lineHeight

  if (leading) {
    if (theme.leading?.[leading]) {
      themeTracking(`leading`, leading)
      lineHeight = generateThemeVariable('leading', leading)
    }
    else {
      lineHeight = h.bracket.cssvar.global.rem(leading)
    }
  }

  if (sizePairs) {
    themeTracking(`text`, [size, 'fontSize'])
    themeTracking(`text`, [size, 'lineHeight'])
    if (sizePairs.letterSpacing) {
      themeTracking(`text`, [size, 'letterSpacing'])
    }

    return {
      'font-size': generateThemeVariable('text', [size, 'fontSize']),
      'line-height': lineHeight ?? `var(--un-leading, ${generateThemeVariable('text', [size, 'lineHeight'])})`,
      'letter-spacing': sizePairs.letterSpacing ? generateThemeVariable('text', [size, 'letterSpacing']) : undefined,
    }
  }

  const fontSize = h.bracketOfLength.rem(size)
  if (lineHeight && fontSize) {
    return {
      'font-size': fontSize,
      'line-height': lineHeight,
    }
  }

  return { 'font-size': h.bracketOfLength.rem(s) }
}

function handleSize([, s]: string[], { theme }: RuleContext<Theme>): CSSObject | undefined {
  if (theme.text?.[s] != null) {
    themeTracking(`text`, [s, 'fontSize'])
    themeTracking(`text`, [s, 'lineHeight'])
    return {
      'font-size': generateThemeVariable('text', [s, 'fontSize']),
      'line-height': `var(--un-leading, ${generateThemeVariable('text', [s, 'lineHeight'])})`,
    }
  }
  else {
    const d = h.bracket.cssvar.global.rem(s)
    if (d)
      return { 'font-size': d }
  }
}

function handlerColorOrSize(match: RegExpMatchArray, ctx: RuleContext<Theme>): CSSObject | (CSSValueInput | string)[] | undefined {
  if (isCSSMathFn(h.bracket(match[1])))
    return handleSize(match, ctx)
  return colorResolver('color', 'text')(match, ctx)
}

export function splitShorthand(body: string, type: string) {
  const [front, rest] = getStringComponent(body, '[', ']', ['/', ':']) ?? []

  if (front != null) {
    const match = (front.match(bracketTypeRe) ?? [])[1]

    if (match == null || match === type)
      return [front, rest]
  }
}

import type { CSSEntries, CSSObject, CSSObjectInput, CSSValueInput, DynamicMatcher, RuleContext, StaticRule, VariantContext } from '@unocss/core'
import type { Theme } from '../theme'
import { symbols, toArray } from '@unocss/core'
import { colorToString, getStringComponent, getStringComponents, isInterpolatedMethod, parseCssColor } from '@unocss/rule-utils'
import { SpecialColorKey } from './constant'
import { h } from './handlers'
import { bracketTypeRe, numberWithUnitRE } from './handlers/regex'
import { cssMathFnRE, cssVarFnRE, directionMap, globalKeywords } from './mappings'
import { detectThemeValue, generateThemeVariable, propertyTracking, themeTracking } from './track'

// #region Number Resolver
export function numberResolver(size: string, defaultValue?: string | number): number | undefined {
  const v = h.number(size) ?? defaultValue

  if (v != null) {
    let num = Number(v)
    if (String(v).endsWith('%')) {
      num = Number(String(v).slice(0, -1)) / 100
    }

    return num
  }
}
// #endregion

// #region Direction with size
/**
 * Provide {@link DynamicMatcher} function returning spacing definition. See spacing rules.
 *
 * @param propertyPrefix - Property for the css value to be created. Postfix will be appended according to direction matched.
 * @see {@link directionMap}
 */
export function directionSize(propertyPrefix: string): DynamicMatcher<Theme> {
  function parseNumberWithUnit(str: string): [number | undefined, string | undefined] {
    const match = str.match(numberWithUnitRE)
    if (match) {
      const [, n, unit] = match
      const num = Number.parseFloat(n)
      if (!Number.isNaN(num))
        return [num, unit]
    }
    return [undefined, undefined]
  }

  function resolveSpace(theme: Theme) {
    let base: number | undefined
    let unit: string | undefined

    if (theme.spacing?.DEFAULT) {
      const [v, u] = parseNumberWithUnit(theme.spacing.DEFAULT)
      if (v != null && u != null) {
        base = v
        unit = u
      }
    }

    return Object.entries(theme.spacing ?? {}).reduce((acc, [key, value]) => {
      const [v, u] = parseNumberWithUnit(value)

      if (v != null && u != null && u === unit) {
        acc[key] = v / base!
      }
      else {
        acc[key] = value
      }

      return acc
    }, {} as Record<string, number | string>)
  }

  return (([_, direction, size]: (string | undefined)[], { theme }): CSSEntries | undefined => {
    if (size != null && direction != null) {
      const spaceMap = resolveSpace(theme)
      let v: string | number | undefined

      const isNegative = size.startsWith('-')
      if (isNegative)
        size = size.slice(1)

      v = numberResolver(size, spaceMap[size as keyof typeof spaceMap])

      if (v != null) {
        if (!Number.isNaN(v)) {
          themeTracking('spacing')
          return directionMap[direction].map(i => [`${propertyPrefix}${i}`, `calc(var(--spacing) * ${isNegative ? '-' : ''}${v})`])
        }
        else {
          themeTracking('spacing', size)
          return directionMap[direction].map(i => [`${propertyPrefix}${i}`, isNegative ? `calc(var(--spacing-${size} * -1)` : `var(--spacing-${size})`])
        }
      }

      v = h.bracket.cssvar.global.auto.fraction.rem(isNegative ? `-${size}` : size)

      if (v != null) {
        return directionMap[direction].map(i => [`${propertyPrefix}${i}`, v])
      }
    }
  }) as DynamicMatcher<Theme>
}
// #endregion

// #region With Colors

// #region Parse color

/**
 * Split utility shorthand delimited by / or :
 */
export function splitShorthand(body: string, type: string) {
  const [front, rest] = getStringComponent(body, '[', ']', ['/', ':']) ?? []

  if (front != null) {
    const match = (front.match(bracketTypeRe) ?? [])[1]

    if (match == null || match === type)
      return [front, rest]
  }
}

/**
 * Parse color string into {@link ParsedColorValue} (if possible). Color value will first be matched to theme object before parsing.
 * See also color.tests.ts for more examples.
 *
 * @example Parseable strings:
 * 'red' // From theme, if 'red' is available
 * 'red-100' // From theme, plus scale
 * 'red-100/20' // From theme, plus scale/opacity
 * '[rgb(100 2 3)]/[var(--op)]' // Bracket with rgb color and bracket with opacity
 * '[rgb(100 2 3)]/[var(--op)]/[in_oklab]' // Bracket with rgb color, bracket with opacity and bracket with interpolation method
 *
 * @param body - Color string to be parsed.
 * @param theme - {@link Theme} object.
 * @return object if string is parseable.
 */
export function parseColor(body: string, theme: Theme) {
  let split
  const [front, ...rest] = getStringComponents(body, ['/', ':'], 3) ?? []

  if (front != null) {
    const match = (front.match(bracketTypeRe) ?? [])[1]

    if (match == null || match === 'color') {
      split = [front, ...rest]
    }
  }

  if (!split)
    return

  let opacity: string | undefined
  let [main, opacityOrModifier, modifier] = split as [string, string | undefined, string | undefined]

  if (isInterpolatedMethod(opacityOrModifier) || isInterpolatedMethod(h.bracket(opacityOrModifier ?? ''))) {
    modifier = opacityOrModifier
  }
  else {
    opacity = opacityOrModifier
  }

  const colors = main
    .replace(/([a-z])(\d)(?![-_a-z])/g, '$1-$2')
    .split(/-/g)
  const [name] = colors

  if (!name)
    return

  let parsed = parseThemeColor(theme, colors)
  if (!parsed && colors.length >= 2) {
    // If the last part of the color is numbers, merge the last two parts
    // e.g. ['foo', 'bar', '1'] should be parsed as ['foo', 'bar1']
    // try the last key is `bar1` in the theme.
    const last = colors.at(-1)
    const secondLast = colors.at(-2)
    if (/^\d+$/.test(last!)) {
      const keys = colors.slice(0, -2).concat([`${secondLast}${last}`])
      parsed = parseThemeColor(theme, keys)
    }
  }

  let { no, keys, color } = parsed ?? {}

  if (!color) {
    const bracket = h.bracketOfColor(main)
    const bracketOrMain = bracket || main

    if (h.numberWithUnit(bracketOrMain))
      return

    if (/^#[\da-f]+$/i.test(bracketOrMain))
      color = bracketOrMain
    else if (/^hex-[\da-fA-F]+$/.test(bracketOrMain))
      color = `#${bracketOrMain.slice(4)}`
    else if (main.startsWith('$'))
      color = h.cssvar(main)

    color = color || bracket
  }

  return {
    opacity,
    modifier: (modifier && h.bracket.cssvar(modifier)) || modifier,
    name,
    no,
    color: color ?? SpecialColorKey[name as keyof typeof SpecialColorKey],
    alpha: h.bracket.cssvar.percent(opacity ?? ''),
    /**
     * Keys means the color is from theme object.
     */
    keys,
    get cssColor() {
      return parseCssColor(this.color)
    },
  }
}

export function parseThemeColor(theme: Theme, keys: string[]) {
  let color: string | undefined
  let no
  let key

  const colorData = getThemeByKey(theme, 'colors', keys)

  if (typeof colorData === 'object') {
    if ('DEFAULT' in colorData) {
      color = colorData.DEFAULT
      no = 'DEFAULT'
      key = [...keys, no]
    }
  }
  else if (typeof colorData === 'string') {
    color = colorData
    key = keys
    no = keys.at(-1)
  }

  if (!color)
    return

  return {
    color,
    no,
    keys: key,
  }
}

export function getThemeByKey(theme: Theme, themeKey: keyof Theme, keys: string[]) {
  const obj = theme[themeKey]
  function deepGet(current: any, path: string[]): any {
    if (!current || typeof current !== 'object')
      return undefined
    if (path.length === 0)
      return current
    // First, check if the path is a flat key (e.g., foo-bar)
    for (let i = path.length; i > 0; i--) {
      const flatKey = path.slice(0, i).join('-')
      if (flatKey in current) {
        const v = current[flatKey]
        if (i === path.length)
          return v
        // look for the rest of the path
        return deepGet(v, path.slice(i))
      }
    }
    return undefined
  }
  return deepGet(obj, keys)
}

// #endregion

// #region Color Resolver

export function colorCSSGenerator(
  data: ReturnType<typeof parseColor>,
  property: string,
  varName: string,
  ctx?: RuleContext<Theme>,
): [CSSObject, ...CSSValueInput[]] | undefined {
  if (!data)
    return

  const { color, keys, alpha, modifier } = data
  const rawColorComment = ctx?.generator.config.envMode === 'dev' && color ? ` /* ${color} */` : ''
  const css: CSSObject = {}

  if (color) {
    const result: [CSSObject, ...CSSValueInput[]] = [css]

    if (Object.values(SpecialColorKey).includes(color)) {
      css[property] = color
    }
    else {
      const alphaKey = `--un-${varName}-opacity`
      const value = keys ? generateThemeVariable('colors', keys) : color
      let method = modifier ?? (keys ? 'in srgb' : 'in oklab')
      if (!method.startsWith('in ') && !method.startsWith('var(')) {
        method = `in ${method}`
      }

      css[property] = `color-mix(${method}, ${value} ${alpha ?? `var(${alphaKey})`}, transparent)${rawColorComment}`
      result.push(defineProperty(alphaKey, { syntax: '<percentage>', initialValue: '100%' }))

      if (keys) {
        themeTracking(`colors`, keys)
        if (!modifier) {
          result.push({
            [symbols.parent]: '@supports (color: color-mix(in lab, red, red))',
            [symbols.noMerge]: true,
            [symbols.shortcutsNoMerge]: true,
            [property]: `color-mix(in oklab, ${value} ${alpha ?? `var(${alphaKey})`}, transparent)${rawColorComment}`,
          })
        }
      }
      if (ctx?.theme) {
        detectThemeValue(color, ctx.theme)
      }
    }

    return result
  }
}

export function colorResolver(property: string, varName: string) {
  return ([, body]: string[], ctx: RuleContext<Theme>): (CSSValueInput | string)[] | undefined => {
    const data = parseColor(body ?? '', ctx.theme)
    if (!data)
      return

    return colorCSSGenerator(data, property, varName, ctx) as (CSSValueInput | string)[]
  }
}

// #endregion

export function colorableShadows(shadows: string | string[], colorVar: string) {
  const colored = []
  shadows = toArray(shadows)
  for (let i = 0; i < shadows.length; i++) {
    // shadow values are between 3 to 6 terms including color
    const components = getStringComponents(shadows[i], ' ', 6)
    if (!components || components.length < 3)
      return shadows

    let isInset = false
    const pos = components.indexOf('inset')
    if (pos !== -1) {
      components.splice(pos, 1)
      isInset = true
    }

    let colorVarValue = ''
    const lastComp = components.at(-1)
    if (parseCssColor(components.at(0))) {
      const color = parseCssColor(components.shift())
      if (color)
        colorVarValue = `, ${colorToString(color)}`
    }
    else if (parseCssColor(lastComp)) {
      const color = parseCssColor(components.pop())
      if (color)
        colorVarValue = `, ${colorToString(color)}`
    }
    else if (lastComp && cssVarFnRE.test(lastComp)) {
      const color = components.pop()!
      colorVarValue = `, ${color}`
    }

    colored.push(`${isInset ? 'inset ' : ''}${components.join(' ')} var(${colorVar}${colorVarValue})`)
  }

  return colored
}

export function hasParseableColor(color: string | undefined, theme: Theme) {
  return color != null && !!parseColor(color, theme)?.color
}

// #endregion

// #region resolve breakpoints
const reLetters = /[a-z]+/gi
const resolvedBreakpoints = new WeakMap<any, { point: string, size: string }[]>()

export function resolveBreakpoints({ theme, generator }: Readonly<VariantContext<Theme>>, key: 'breakpoint' | 'verticalBreakpoint' = 'breakpoint') {
  const breakpoints: Record<string, string> | undefined = (generator?.userConfig?.theme as any)?.[key] || theme[key]

  if (!breakpoints)
    return undefined

  if (resolvedBreakpoints.has(theme))
    return resolvedBreakpoints.get(theme)

  const resolved = Object.entries(breakpoints)
    .sort((a, b) => Number.parseInt(a[1].replace(reLetters, '')) - Number.parseInt(b[1].replace(reLetters, '')))
    .map(([point, size]) => ({ point, size }))

  resolvedBreakpoints.set(theme, resolved)
  return resolved
}

export function resolveVerticalBreakpoints(context: Readonly<VariantContext<Theme>>) {
  return resolveBreakpoints(context, 'verticalBreakpoint')
}
// #endregion

// #region Global static & defineProperty
export function makeGlobalStaticRules(prefix: string, property?: string): StaticRule[] {
  return globalKeywords.map(keyword => [`${prefix}-${keyword}`, { [property ?? prefix]: keyword }])
}

export function defineProperty(
  property: string,
  options: { syntax?: string, inherits?: boolean, initialValue?: unknown } = {},
): CSSValueInput {
  const {
    syntax = '*',
    inherits = false,
    initialValue,
  } = options

  const value: CSSObjectInput = {
    [symbols.shortcutsNoMerge]: true,
    [symbols.noMerge]: true,
    [symbols.variants]: () => [
      {
        parent: '',
        layer: 'properties',
        selector: () => `@property ${property}`,
      },
    ],
    syntax: JSON.stringify(syntax),
    inherits: inherits ? 'true' : 'false',
  }
  if (initialValue != null) {
    value['initial-value'] = initialValue as keyof CSSObjectInput
  }
  propertyTracking(property, initialValue ? String(initialValue) : 'initial')
  return value
}
// #endregion

// #region Basic util functions
export function isCSSMathFn(value: string | undefined) {
  return value != null && cssMathFnRE.test(value)
}

export function isSize(str: string) {
  if (str[0] === '[' && str.slice(-1) === ']')
    str = str.slice(1, -1)
  return cssMathFnRE.test(str) || numberWithUnitRE.test(str)
}

export function camelize(str: string) {
  return str.replace(/-(\w)/g, (_, c) => c ? c.toUpperCase() : '')
}

export function hyphenate(str: string) {
  return str.replace(/(?:^|\B)([A-Z])/g, '-$1').toLowerCase()
}

export function compressCSS(css: string, isDev = false) {
  if (isDev)
    return css.trim()
  return css.trim().replace(/\s+/g, ' ').replace(/\/\*[\s\S]*?\*\//g, '')
}
// #endregion

import type { Postprocessor } from '@unocss/core'
import type { PresetWind4Options } from '..'

export function important({ important: option }: PresetWind4Options): Postprocessor[] {
  if (option == null || option === false)
    return []

  const wrapWithIs = (selector: string) => {
    if (selector.startsWith(':is(') && selector.endsWith(')'))
      return selector

    // handle pseudo
    if (selector.includes('::'))
      return selector.replace(/(.*?)((?:\s\*)?::.*)/, ':is($1)$2')

    return `:is(${selector})`
  }

  return [
    option === true
      ? (util) => {
          // If the util is a property layer, we should not add `!important` to it
          if (util.layer === 'properties')
            return

          util.entries.forEach((i) => {
            if (i[1] != null && !String(i[1]).endsWith('!important'))
              i[1] += ' !important'
          })
        }
      : (util) => {
          if (!util.selector.startsWith(option))
            util.selector = `${option} ${wrapWithIs(util.selector)}`
        },
  ]
}

