      envMode: 'dev',
      presets: [
        presetWind4({ preflights: { reset: false } }),
      ],
      theme: {
        colors: {
          foo: 'var(--colors-bar)',
          bar: 'var(--colors-baz-bcd, #000)',
          baz: {
