    const css = getLayer('theme')

    expect(css).toMatchInlineSnapshot(`
      "/* layer: theme */
      :root, :host {
      --spacing: 4px;
      --ui-red-DEFAULT: oklch(70.4% 0.191 22.216);
      }"
    `)
  })

