  it('important selector does not break property layer', async () => {
    const uno = await createGenerator({
      envMode: 'dev',
      presets: [
        presetWind4({
          important: '#__nuxt',
          preflights: { reset: false },
        }),
      ],
    })

    const { css } = await uno.generate('text-red')

    // `text-red` relies on `--un-text-opacity` with a corresponding `@property`
    // definition in the `properties` layer. When `important` is a selector,
    // that layer must not be scoped, otherwise the `@property` rule would be
    // invalid and the variable would appear undefined in devtools.
    expect(css).toContain('@property --un-text-opacity')
    expect(css).not.toContain('#__nuxt :is(@property --un-text-opacity)')
    expect(css).toContain('.text-red')
  })

